const webhookData = $json.body || {};

// VERIFICAMOS SI ES META CLOUD API
if (webhookData.entry && webhookData.entry[0].changes) {
    const value = webhookData.entry[0].changes[0].value;
    // Si es un status update (read/delivered), lo ignoramos devolviendo vacio
    if (value.statuses) return []; 

    const msg = value.messages ? value.messages[0] : {};
    return [{
        json: {
            chat_id: msg.from || '',
            instancia: 'Meta Cloud API',
            server: 'Meta',
            usuario: value.contacts ? value.contacts[0].profile.name : 'Usuario',
            id: msg.id || '',
            'tipo de mensaje': msg.type || 'unknown',
            texto: msg.text ? msg.text.body : '',
            fromMe: false
        }
    }];
}

// FALLBACK PARA EVOLUTION API VIEJA
const data = webhookData.data || webhookData;
return [{
    json: {
        chat_id: data.key?.remoteJid || '',
        instancia: webhookData.instance || '',
        server: webhookData.server_url || '',
        usuario: data.pushName || '',
        id: data.key?.id || '',
        'tipo de mensaje': data.messageType || 'conversation',
        texto: data.message?.conversation || data.message?.extendedTextMessage?.text || '',
        fromMe: data.key?.fromMe || false
    }
}];

const webhookData = $('Webhook WA').first().json.body || {};

// META CLOUD API FORMAT
if (webhookData.entry && webhookData.entry[0].changes) {
    const value = webhookData.entry[0].changes[0].value;
    if (value.statuses) return []; 
    if (!value.messages || value.messages.length === 0) return [];

    let phone = value.messages[0].from;
    let final_text = "Me gustaría saber más.";
    if ($input.first().json.texto) {
        final_text = $input.first().json.texto;
    } else if (value.messages[0].text && value.messages[0].text.body) {
        final_text = value.messages[0].text.body;
    }
    return [{ json: { phone: phone, text: final_text } }];
}

// EVOLUTION API FORMAT
const data = webhookData.data || webhookData;
if (data.key?.fromMe === true || data.fromMe === true) { return []; }
let rawPhone = data.key?.remoteJid || data.sender || '';
let phone = rawPhone.split('@')[0].replace(/\D/g, '');
if (!phone) return []; 
let final_text = $input.first().json.texto || $input.first().json.text || data.message?.conversation || data.message?.extendedTextMessage?.text || "Me gustaría saber más";

return [{ json: { phone: phone, text: final_text } }];

const results = [];
let originalVapiData = null;
const possibleNames = ["Webhook VAPI", "Webhook VAPI ⚡", "Webhook", "Webhook ⚡"];
for (let name of possibleNames) {
    try {
        originalVapiData = $(name).first().json.body || $(name).first().json;
        if (originalVapiData) break;
    } catch (e) { }
}
if (!originalVapiData) { originalVapiData = $input.all()[0].json.body || $input.all()[0].json; }
let phoneToUse = null;
let textToUse = "🚀 ¡Hola! Soy Alex de The GenerArise. Aquí tienes tu auditoría y el enlace que solicitaste: https://generarise.space/#contacto";

if (originalVapiData?.message?.call?.customer?.number) {
    phoneToUse = originalVapiData.message.call.customer.number;
}
if (!phoneToUse && originalVapiData?.message?.toolCalls?.[0]?.function?.arguments) {
    let args = originalVapiData.message.toolCalls[0].function.arguments;
    if (typeof args === 'string') { try { args = JSON.parse(args); } catch(e){} }
    phoneToUse = args?.phone || args?.number;
}
if (!phoneToUse) {
    const sd = originalVapiData?.message?.call?.analysis?.structuredData || originalVapiData?.message?.call?.artifact?.structuredData;
    if (sd) { phoneToUse = sd.phone || sd.number || sd.telefono; }
}
if (!phoneToUse) {
    let transcriptCompleto = "";
    if (originalVapiData?.message?.artifact?.transcript) {
        transcriptCompleto = originalVapiData.message.artifact.transcript;
    } else if (originalVapiData?.message?.artifact?.messages) {
        let arreglo = originalVapiData.message.artifact.messages;
        transcriptCompleto = arreglo.map(m => m.message).join(" ");
    }
    if (transcriptCompleto) {
        let textoLimpio = transcriptCompleto.replace(/[\s\-]/g, '');
        let coincidencia = textoLimpio.match(/\d{10,13}/);
        if (coincidencia) { phoneToUse = coincidencia[0]; }
    }
}
if (phoneToUse) {
    phoneToUse = String(phoneToUse).replace(/\D/g, ''); 
    if (phoneToUse.length === 10) {
        phoneToUse = '521' + phoneToUse; 
    } else if (phoneToUse.length === 12 && phoneToUse.startsWith('52')) {
        phoneToUse = '521' + phoneToUse.slice(2);
    }
}
if (phoneToUse && phoneToUse.length >= 10) {
    results.push({ json: { number: phoneToUse, text: textToUse } });
    return results; 
} else {
    return []; 
}

const raw = $json.output || $json.text || $json.message || $input.item.json.output || '';
const cleanMessage = raw.split('---END---')[0].split('--END---')[0].trim();
const finalMessage = cleanMessage || '¡Gracias por tu tiempo! Si en algún momento querés explorar cómo la IA puede ayudar a tu negocio, acá estamos. ¡Éxitos! 🙌';
return [{ json: { cleanMessage: finalMessage } }];
